SELECT ?partLabel ?part ?v ?u ?low ?high WHERE {
  <https://www.purl.org/futuram/example#V0101010102_2025> futuram:hasCompositionStatement ?stmt .
  ?stmt futuram:hasPartRelation ?pr .
  ?pr futuram:refersTo ?part ;
